var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"좋아! 다들 무허가 함선에 대한 수색을 개시한다!","JPN":"よし！　総員無許可艦船についての捜索を開始する！","ENG":"All right! Commence the search of this unlicensed ship!","TWN":"好！大家開始針對無照艦船進行調查！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"자, 승객들은 이쪽으로 오세요! 직원들은 이쪽! 진찰 후 간단한 조사가 있을 겁니다!","JPN":"さあ、乗客の方はこちらにどうぞ！　職員はこちらに！　診察の後に、簡単な調査が行われる予定です！","ENG":"Everyone, please step this way! The staff go over go there! After a quick checkup, you will have a brief interview with us!","TWN":"乘客站這邊！員工站這邊！稍後會進行簡單的調查！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현장에 알린다. 종업원들과 무장한 직원들을 분리하도록, 이상.</color>","JPN":"<color=#ffd34c>現場に告げる。従業員と武装した職員を分離するように、以上。</color>","ENG":"<color=#ffd34c>Attention all units. Make sure to separate the staff from the armed ones, over.</color>","TWN":"<color=#ffd34c>通知現場，普通員工和武裝員工要分開，以上。</color>"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아니, 내가 언제 엔진에 탈나게 하라고 했지 함선을 탈취하라고 했어?!","JPN":"いやね、私はエンジンを壊せと言っただけで、艦船を奪取しろとは言わなかったわよ！？","ENG":"Hey, I told you to stop the engine, not steal the entire ship!","TWN":"拜託，我是叫你們弄壞引擎，誰說要迫降艦船啦？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"내가 못 살아, 정말! 이래서 애들 말에 속으면 안 됐는데!!","JPN":"もう、何なのよ！　これだから子どもたちの言葉に騙されちゃダメなのに！！","ENG":"I can believe this! I should've never listened to you...!","TWN":"我會氣死！果然不該相信你們的！！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"죄송합니다…….","JPN":"すみません……","ENG":"We're sorry...","TWN":"對不起……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"미, 미안하다니까…….","JPN":"ご、ごめんってば……","ENG":"W-we said we're sorry, didn't we...?","TWN":"對…對不起嘛……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그래도 별일 없이 끝났으니까 결과적으로는 괜찮지 않아?","JPN":"でも何事もなく終わったんだから、結果オーライじゃない？","ENG":"Although, nothing went seriously wrong in the end. So aren’t we good?","TWN":"不過至少算是平安落幕，以結果來說應該還可以吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"별일 없기는 뭐가 별일이 없어. 이 난장판이 났는데.","JPN":"何が何事もなかったよ。この騒ぎどうするの。","ENG":"Are you kidding me? I mean, look at this mess!","TWN":"搞得亂七八糟的還說什麼平安落幕！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"인터넷은 지금 난리야. 도시 한복판에 함선만 한 양 괴물이 나타났다면서.","JPN":"今ネットでは大騒ぎよ。都市の真ん中に、艦船ほどデカい羊が現れたって。","ENG":"Everyone on the internet is talking about some giant sheep monster the size of a ship appearing in the middle of the city!","TWN":"現在網路上吵成一團，說什麼在市中心出現一隻和艦船一樣大的怪物羊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐, 일단 그래도 무사해서 다행이야.","JPN":"まあ、でもとりあえず無事でよかった。","ENG":"But... I'm glad that you're all safe.","TWN":"總之幸好大家都沒事，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"골칫거리였던 헤이븐 패거리까지 이렇게 일망타진하고.","JPN":"悩みの種だったヘイブンの連中までこうやって一網打尽できたしね。","ENG":"You even took down the pain-in-my-butt Haven Organization.","TWN":"還將令人頭疼的天堂惡霸一網打盡。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"꼭 설득하겠다더니, 약속 지켰네. 고생했겠다.","JPN":"絶対説得するっていう約束、守れたんだね。ご苦労様。","ENG":"And you held up your part of the deal by persuading Mark. Good job.","TWN":"還真的有遵守約定去說服上面的人呢，應該很辛苦吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흥. 고생은. 여태 겁 먹고 구경만 하던 윗분들이 이상한 거지.","JPN":"ふん、そんなに苦労してないわよ。今まで怯えて見てるばかりだった上層部がおかしいの。","ENG":"Hmph! Good job my foot. The higher-ups are the weird ones who did nothing and just watched it unfold out of cowardice.","TWN":"哼，有什麼好辛苦的，那些一直膽小怕事只敢在一旁觀望的人才奇怪吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"봐 봐, 검은 평의회는 마지막까지 결국 코빼기도 안 비췄잖아.","JPN":"ほら、黒の評議会は最後まで顔も出さなかったじゃない。","ENG":"Look. The Dark Council is nowhere to be seen right now.","TWN":"你們看，黑暗評議會到最後大氣都不敢吭一聲！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! 리코리스!","JPN":"あっ！　リコリス！","ENG":"Oh! Lycoris!","TWN":"喔！是莉克麗絲！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"에엑……?! 코핀 사장님네 딸이잖아?","JPN":"ええっ……！？　コフィン社長の娘？","ENG":"W-what...?! Aren't you Coffin Company Boss's daughter?","TWN":"咦……？！是科芬公司老闆的女兒？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"네, 네가 왜 여기 있어? 아니, 계세요?","JPN":"な、なんであんたここにいるの？　いや、いるんですか？","ENG":"W-what are you doing here? I mean, ma'am?","TWN":"你…呃，不是，您為何會在這呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"친구들이랑 놀러 왔어. 술래잡기도 하고 놀이기구도 타고, 그리고……","JPN":"友達と遊びに来たの。かくれんぼに、アトラクションに、それに……","ENG":"I'm playing with my friends! We played tag, rode a roller coaster, and...","TWN":"我和朋友來玩的，我們有玩鬼抓人，也有搭遊樂器材，還有……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"유령의 집 탐험도 하고. 그치?","JPN":"お化け屋敷も探検した。ね？","ENG":"Don't forget the haunted house.","TWN":"還有去鬼屋探險對吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그치~!","JPN":"ね～！","ENG":"Oh, right!","TWN":"對啊～！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L31_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하아…… 다행이다. 메이드장이 알면 웃는 얼굴로 하루 종일 잔소리를 해댔을 텐데.","JPN":"はあ……よかった。メイド長が知ったら笑顔で一日中小言をいわれてたよ。","ENG":"*Sigh...* Thank goodness. If Chief Maid found out about this, I'd be listening to her lectures for a whole day.","TWN":"哈……那就好，要是女僕長知道的話，一定會笑笑地唸我一整天。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"그런데 이상하네, 그 사장님이 보호자 한 명 안 붙여 뒀나?","JPN":"でもおかしいわね。あの社長が保護者を一人もつけてないなんて。","ENG":"But didn't that Boss assign you a guardian?","TWN":"可是有點奇怪，那個老闆沒有派人在你身邊跟著嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"미래전략실장님의 안전 확보 확인. 철수하겠습니다, 부전대장님.","JPN":"未来戦略室長の安全確保を確認。撤収いたします、副戦隊長。","ENG":"Confirming that the head of Future Strategy Department is safe and sound. Returning to HQ, Deputy Commander.","TWN":"副戰隊長，確認未來戰略室長安全無虞，先行撤退。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"이제야 좀 마음 놓겠군. 지켜보는 내내 비복근이 떨려서 견딜 수가 없었어.","JPN":"やっと安心できる。見守っている間中、ずっとふくらはぎが震えて死ぬかと思ったよ。","ENG":"I can finally stop worrying about it. My stomach muscles were twitching so much that I couldn't stand to watch.","TWN":"現在終於可以稍微放心，在旁邊看的時候整個緊張到胃痛到不行。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"글린다, 울지 마. 루루랑은 금방 다시 만날 수 있을 거야.","JPN":"グリンダ、泣かないで。ルルとはすぐにまた会えるはずだよ。","ENG":"Don't cry, Glinda. We'll see Lulu real soon.","TWN":"格琳達，別哭，很快就可以再見到露露的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"누가 울었다고 그래, 바보야. 안 울었어.","JPN":"泣いてないよ、バカ。泣いてないったら。","ENG":"Who said I was crying, stupid? I didn’t cry.","TWN":"誰哭啦，你這傻瓜，我才沒哭。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"바보? 바보라고 했겠다!","JPN":"バカ？　バカって言ったな！","ENG":"Stupid? You called me stupid!","TWN":"傻瓜？原來我是傻瓜！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"함선을 맨몸으로 막겠다는 애를 바보라고 부르지 그럼 뭐라고 부르냐!?","JPN":"艦船を体だけで止めるって言い出す子がバカじゃかなったら何がばかだよ！？","ENG":"What else am I supposed to call someone who tried to stop a ship from crashing with her own body?!","TWN":"赤手空拳說要阻止艦船的人不是傻瓜的話，誰才是傻瓜！？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……글린다 쟤, 괜찮으려나. 기운 차려야 할 텐데.","JPN":"……グリンダ、大丈夫かな。元気出してくれればいいけど。","ENG":"You think Glinda's gonna be all right? I hope she brightens up.","TWN":"……格琳達，她沒關係吧？希望她打起精神來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"우리 중에 제일 어른스럽잖아. 스스로 잘할 수 있겠지.","JPN":"ワタシたちの中では一番大人でしょう。自分で何とかできるはずだよ。","ENG":"She's the most mature out of all of us. I'm sure she'll be fine.","TWN":"她是我們當中最年長的，自己可以處理好的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어른이라…….","JPN":"大人か……","ENG":"Mature, eh...?","TWN":"最年長的……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"찾았습니다! 여기 간부진들입니다!","JPN":"見つけました！　幹部陣です！","ENG":"I found them! The consiglieres are here!","TWN":"找到了！幹部都在這裡！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"모두 머리 뒤로 손 올려!","JPN":"全員、手を上げて頭の後ろに回せ！","ENG":"Hands above your head!","TWN":"全都把手舉起來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"고등급 카운터다! 조금이라도 수상한 낌새를 보이면 모든 화력을 투입해라!","JPN":"ハイレベルのカウンターだ！　少しでも怪しい行動を見せたら全火力を投入しろ！","ENG":"They're high-ranking Counters! If they so much as twitch shoot them with everything you've got!","TWN":"有高階制裁者！要是發現情況不對，就立刻動用所有火力！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"다들 진정하세요. 저항하지 않겠습니다.","JPN":"皆さん、落ち着いてください。抵抗するつもりはありません。","ENG":"Calm down, everyone. I won't resist.","TWN":"不要開槍，我們不會反抗。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"제가 헤이븐입니다. 물으시는 대로 전부 답해 드릴게요.","JPN":"僕がヘイブンです。聞くことにすべてお答えします。","ENG":"I am Haven. I’ll answer every one of your questions.","TWN":"我就是天堂，我會配合你們的調查。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"루트!","JPN":"ルート！","ENG":"Root!","TWN":"路特！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"아, 시그마.","JPN":"あ、シグマ。","ENG":"Sigma.","TWN":"喔，西格瑪。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"미안해. 기껏 헤이븐 랜드에 와 줬는데 즐거운 시간은커녕 고생만 시켰어.","JPN":"ごめん。せっかくヘイブンランドに来てくれたのに､楽しい時間どころか苦労ばかりかけちゃったね｡","ENG":"I’m sorry. You came all this way to Havenland, but I didn't show you a good time.","TWN":"對不起，難得來一趟天堂樂園，卻沒能讓你玩得盡興，反而受那麼多苦。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응? 고생 안 했는데? 나 지금 정말 즐거워!","JPN":"うん？　苦労してないよ？　私、今本当に楽しいんだもん！","ENG":"Hmm? What do you mean? I had a blast!","TWN":"嗯？受什麼苦？我現在超開心欸！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"루루가 엄청 크고 푹신푹신한 양이라는 것도 알았고.","JPN":"ルルがすっごく大きくてふわふわの羊だってことも知ったし。","ENG":"I learned that Lulu is a huuuge fluffy sheep!","TWN":"我發現露露是一隻超大隻軟綿綿的羊，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"나쁜 마녀의 손아귀에서 친구들도 구해냈고.","JPN":"悪い魔女の手から友達も助けたし。","ENG":"And I saved my friends from that evil witch!","TWN":"還從壞巫婆手中救出朋友，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"유령의 집에서 보물찾기도 하고, 술고래 아줌마 배가 얼마나 튼튼한지도 봤고!","JPN":"お化け屋敷で宝探しもして、のんべえおばさんのお腹がどんなに丈夫なのかも見たし！","ENG":"And I did a treasure hunt inside a haunted house, and I also saw how tough Ms. Hard Drinker's stomach was!","TWN":"還在鬼屋裡尋寶，看到酒鬼阿姨的肚子有多能裝。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그리고, 그리고……!","JPN":"それから、それから……！","ENG":"And, and...!","TWN":"還有還有……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……고마워, 시그마. 녀석보다 너와 조금 더 빨리 만났으면 좋았을 텐데.","JPN":"……ありがとう、シグマ。あいつより君ともっと早く出会えたらよかったのに。","ENG":"...Thank you, Sigma. I wish I had met you before I met him.","TWN":"……西格瑪，謝謝你。真希望我先遇見的是你，而不是那傢伙。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응? 왜? 루트도 어디 가?","JPN":"うん？　なんで？　ルートもどこか行くの？","ENG":"Hmm? Huh? Where are you going, Root?","TWN":"嗯？怎麼這麼說？路特也要走了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"으응. 있잖아, 사실 난 노는 게 너무 좋아서 숙제도 미뤄 두고 살았거든.","JPN":"ううん。実は遊ぶことに夢中になって宿題もしないまま生きてきたんだ。","ENG":"Well... I was so busy playing that I forgot to do any of my homework.","TWN":"嗯嗯，對啊。因為我光顧著玩，功課都沒寫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"어허. 그럼 안 되지. 난 미래전략실장이라 매일 아침 할아버지 포신을 닦아 주거든.","JPN":"めっ。それじゃダメだよ。私は未来戦略室長だから、毎朝おじいちゃんの砲身を磨いてあげてるんだ。","ENG":"Come on, that's not good. I always clean Grandpa's gun barrel every day because I'm the head of the Future Strategy Department.","TWN":"吼，這樣不行喔。像我是未來戰略室長，所以每天早上都會把爺爺的砲筒擦得亮晶晶的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그럼 할아버지가 무척 기뻐해.","JPN":"そうするとおじいちゃんがとても喜んでくれるんだよ。","ENG":"He’s really happy when I do that.","TWN":"那爺爺就會很開心～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"맞아. 디 엔드 랜드에서 너와 술래잡기를 할 때 떠올랐어. 지금 이럴 때가 아니라고.","JPN":"そうだね。ジ・エンドランドで君と鬼ごっこしてた時に思いついたんだ。今こうしてる場合じゃないって。","ENG":"That’s right. I realized when we were playing tag at The End Land... that there’s something I have to do.","TWN":"對啊，我想到在終點站樂園和你一起玩鬼抓人的時候，但現在不是玩樂的時候。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"나는…… 아무것도 제대로 책임지지 않았으니까.","JPN":"僕は……何一つまともに責任を取ってなかったから。","ENG":"Because I... I've never taken responsibility for anything.","TWN":"因為……我沒有負起任何責任。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"형님! 어린애 앞에서 그게 뭡니까! 기운 내십시오!","JPN":"兄貴！　子どもの前で何ですか！　元気を出してください！","ENG":"Boss! Why are you like that in front of that kid! Keep your chin up, sir!","TWN":"大哥！您在小朋友面前這樣成何體統！打起精神來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"허드슨, 우린 체포된 신세야. 목소리 낮춰.","JPN":"ハドソン、私たちは逮捕された身だ。声を抑えろ。","ENG":"We’re under arrest, Hudson. Keep your voice down.","TWN":"哈德森，我們現在是被逮捕的犯人，聲音小一點。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"뭐……? 자, 잠깐. 가면은 안 썼는데 어떻게 알아 봐?","JPN":"え……？　ちょ、ちょっと。仮面を被ってないのにどうしてわかるんだ？","ENG":"What...? W-wait...! I'm not wearing my mask... How did you know it's me?","TWN":"什麼……？等等，我又沒戴面具，你們怎麼認得出我來？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"네가 형님이 아니면, 형님이 아무 얼치기 잡아다 대타로 세웠겠어?","JPN":"あんたが兄貴じゃないなら、適当な間抜けを連れてきて兄貴の代わりにしたってことになるけど？","ENG":"If you're not our boss, do you think he would use a fool like you as his double?","TWN":"你不是大哥的話，難道是大哥隨便找來的分身嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"이런 일을 겪고 못 알아채는 게 멍청이지.","JPN":"こんなこともあったのにわからない方がバカなんだよ。","ENG":"You'd have to be an idiot not to notice after all we've been through.","TWN":"經歷這些事還認不出來的話，根本是蠢蛋吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그, 그래…… 이제 내가 얼마나 한심한 인간인지 다들 알았겠네.","JPN":"そ、そうか……もうみんな、僕がどんなに情けない人間なのかわかっちゃったんだね。","ENG":"Y-yeah... I guess all of you know how pathetic of a person I am now.","TWN":"是啊……現在大家都知道我是個多沒用的人了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"무슨 말씀을 하십니까. 저는 다른 녀석들처럼 형님 가면에 혹한 적 없습니다.","JPN":"何を言ってるんですか。俺は他のやつらみたいに兄貴の仮面に惑わされたことなんてありません。","ENG":"Don't say that. Unlike the others, I've never been fooled by your mask.","TWN":"您說這什麼話！我可不像其他傢伙，我從未被大哥的面具給迷惑過。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"나도 마찬가지야. 내가 받았던 도움은 그럴싸한 빈말로 될 게 아니었으니까.","JPN":"私もよ。私が受けた恩はそれっぽいお世辞でできるようなことじゃなかったから。","ENG":"Same here. Because I know the words you said to me have meaning.","TWN":"我也是，因為我受到的幫助不是假的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"죄송합니다, 형님. 제가 너무 안일했습니다.","JPN":"申し訳ありません、兄貴。私が甘かったのです。","ENG":"My apologies, boss. I was too careless.","TWN":"大哥抱歉，都怪我太安逸，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"형님의 헤이븐 랜드를 망가뜨린 점…… 무어라 드릴 말씀이 없습니다.","JPN":"兄貴のヘイブンランドを壊したこと……どうお詫びすればいいか。","ENG":"The fact that I destroyed Havenland... I have no excuse for that.","TWN":"害得大哥的天堂樂園變成這樣……我無話可說。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"너희들…….","JPN":"みんな……","ENG":"Everyone...","TWN":"你們……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"루트, 친구가 많구나? 나도 더 많이 사귀어야겠다.","JPN":"ルート、友達がいっぱいいるんだね？　私ももっと友達いっぱい作らなきゃ。","ENG":"You have so many friends, Root! I should make more friends too.","TWN":"路特，你有好多朋友喔！我也要交更多的朋友！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"……그 말대로야, 시그마. 노는 것도 좋지만 친구들을 지키는 게 먼저지.","JPN":"……そのとおりだよ、シグマ。遊ぶのもいいけど、まずは友達を守らないとね。","ENG":"...You're right, Sigma. Playing is fun, but protecting friends should come first.","TWN":"……說的沒錯，西格瑪。玩樂是很開心，但更重要的是要守護朋友。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응. 친구들 없이 혼자 놀면 금방 심심해져.","JPN":"うん。一人で遊でもすぐ飽きちゃうもん。","ENG":"Yes. It's no fun playing alone.","TWN":"嗯，沒有朋友的話，一個人玩很快就會無聊的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그래서 결심했어. 밀린 숙제를 끝내고 돌아오자고.","JPN":"だから決めたんだ。たまってる宿題を終わらせてから帰ってこようって。","ENG":"That's why I made up my mind. I'm going to do all my homework and come back.","TWN":"所以我決定了，我要把堆積的功課寫完再回來！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그 때는 홀가분하게…… 오늘보다 더 신나게 놀자.","JPN":"その時にはさっぱりした心で……今日よりもっと楽しく遊ぼう。","ENG":"And when I do... Let's have more fun than we had today!","TWN":"到時候就可以更放心地玩……可以比今天還開心！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗, 루트!! 잠깐만!","JPN":"あっ、ルート！！　ちょっと待って！","ENG":"Oh, Root!! Wait!","TWN":"哎呀，路特！！先等一下！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"루트는 오늘 어땠어?","JPN":"ルートは今日どうだった？","ENG":"How was your day, Root?","TWN":"那路特今天還好嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"정말 즐거운 하루였어.","JPN":"本当に楽しい一日だったよ。","ENG":"It was a great day.","TWN":"今天真的很開心，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"꼭 요정의 마법에라도 걸린 것처럼.","JPN":"まるで妖精の魔法にでもかけられたみたいに。","ENG":"Like a fairy cast a spell on me.","TWN":"感覺好像真的有精靈的魔法一樣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THMEA_SAD_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};